tool chat_token_stream { description: "streaming" effects: <stream:drop_oldest> }
flow Chat() -> String { step Generate { ask: "hi" apply: chat_token_stream } }
axonendpoint ChatEndpoint { method: POST path: "/chat" execute: Chat }

